@import url("https://fonts.googleapis.com/css2?family=Inter:wght@300;400;700;900&display=swap");
@import url("fontawesome-all.min.css");

/*
ndev consulting
*/

:root {
	/* Modular Scale 1.25 (Major Third) */
	/* Mobile Base: 16px, Desktop Base: 18px */
	--text-xs: clamp(0.8rem, 0.17vw + 0.76rem, 0.89rem);
	--text-sm: clamp(1rem, 0.34vw + 0.91rem, 1.19rem);
	--text-base: clamp(1.25rem, 0.61vw + 1.1rem, 1.58rem);
	--text-lg: clamp(1.56rem, 1vw + 1.31rem, 2.11rem);
	--text-xl: clamp(1.95rem, 1.56vw + 1.56rem, 2.81rem);
	--text-2xl: clamp(2.44rem, 2.38vw + 1.85rem, 3.75rem);
	--text-3xl: clamp(3.05rem, 3.54vw + 2.17rem, 5rem);

	/* Tracking */
	--tracking-tighter: -0.04em;
	--tracking-tight: -0.02em;
	--tracking-normal: 0;
	--tracking-wide: 0.05em;

	/* Line Height */
	--leading-tight: 1.1;
	--leading-normal: 1.6;
	--leading-relaxed: 1.75;

	/* Colors (Default / Dark-ish Background) */
	--bg-color: #111111;
	/* Fallback */
	--text-color: #ffffff;
	/* White text for contrast */
	--text-muted: #cccccc;
	--border-color: #ffffff;
	--accent-color: #5F9BD9;
	--overlay-bg: rgba(0, 0, 0, 0.5);
}

/* Light Mode Overrides (Future Proofing) */
html.light {
	--bg-color: #ffffff;
	--text-color: #2c2c2c;
	--text-muted: #666666;
	--border-color: #2c2c2c;
	--overlay-bg: rgba(255, 255, 255, 0.85);
}

/* Dark Mode (Explicit) - matches default for now */
html.dark {
	--bg-color: #111111;
	--text-color: #ffffff;
	--text-muted: #cccccc;
	--border-color: #ffffff;
	--overlay-bg: rgba(0, 0, 0, 0.5);
}

